const odoo = "https://ocean-tech-0326.odoo.com/jsonrpc";
const db = "ocean-tech-0326", uid = 2, pwd = "M1ercole$";

async function odooCall(model, method, args, kwargs) {
  const body = {jsonrpc:"2.0",method:"call",id:1,params:{
    service:"object",method:"execute_kw",
    args:[db,uid,pwd,model,method,args],
    kwargs: kwargs || {}
  }};
  const resp = await this.helpers.httpRequest({
    method: "POST",
    url: odoo,
    body: body,
    json: true,
    headers: {"Content-Type": "application/json"}
  });
  if (resp.error) throw new Error(resp.error.message);
  return resp.result || 0;
}

const active = [["active","=",true]];
const total = await odooCall.call(this, "product.template", "search_count", [active]);
const con_precio = await odooCall.call(this, "product.template", "search_count", [[...active,["list_price",">",0]]]);
const con_imagen = await odooCall.call(this, "product.template", "search_count", [[...active,["image_1920","!=",false]]]);
const con_desc = await odooCall.call(this, "product.template", "search_count", [[...active,["description_sale","!=",false]]]);
const con_sku = await odooCall.call(this, "product.template", "search_count", [[...active,["default_code","!=",false]]]);
const sin_sku = total - con_sku;

const completos = await odooCall.call(this, "product.template", "search_count", [
  [...active,["list_price",">",0],["image_1920","!=",false],["default_code","!=",false]]
]);
const pct = total > 0 ? Math.round(completos/total*100) : 0;

// Top 20 incomplete WITHOUT image field (lightweight)
const incompletos = await odooCall.call(this, "product.template", "search_read",
  [[...active, "|","|",["image_1920","=",false],["list_price","=",0],["default_code","=",false]]],
  {fields: ["id","name","default_code","list_price","description_sale"], limit: 20, order: "id desc"}
);

const incomplete_list = (incompletos || []).map(p => {
  const issues = [];
  if (!p.list_price || p.list_price === 0) issues.push("precio");
  if (!p.default_code) issues.push("SKU");
  if (!p.description_sale) issues.push("descripcion");
  return {id: p.id, name: (p.name||"").substring(0,55), sku: p.default_code||"-", issues};
});

return [{json:{
  total, con_precio, con_imagen, con_desc, con_sku, sin_sku,
  completos, completeness_pct: pct,
  missing_image: total - con_imagen,
  missing_price: total - con_precio,
  missing_desc: total - con_desc,
  missing_sku: sin_sku,
  incomplete_top50: incomplete_list
}}];

